"use strict";(self.webpackChunkweaver_orm_docs=self.webpackChunkweaver_orm_docs||[]).push([[412],{7593(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"category","label":"Getting Started","collapsed":false,"items":[{"type":"link","label":"Einf\xfchrung","href":"/weaverORM/de/docs/","docId":"intro","unlisted":false},{"type":"link","label":"Installation","href":"/weaverORM/de/docs/installation","docId":"installation","unlisted":false},{"type":"link","label":"Schnellstart","href":"/weaverORM/de/docs/quick-start","docId":"quick-start","unlisted":false},{"type":"link","label":"Symfony-Konfiguration","href":"/weaverORM/de/docs/configuration","docId":"configuration","unlisted":false}],"collapsible":true},{"type":"category","label":"Entity Mapping","items":[{"type":"link","label":"Entity-Mapping","href":"/weaverORM/de/docs/entity-mapping","docId":"entity-mapping","unlisted":false},{"type":"link","label":"Beziehungen","href":"/weaverORM/de/docs/relations","docId":"relations","unlisted":false},{"type":"link","label":"Eingebettete Objekte","href":"/weaverORM/de/docs/embeddable","docId":"embeddable","unlisted":false},{"type":"link","label":"Vererbungs-Mapping","href":"/weaverORM/de/docs/inheritance","docId":"inheritance","unlisted":false},{"type":"link","label":"Concerns und Traits","href":"/weaverORM/de/docs/concerns","docId":"concerns","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Entity Workspace","items":[{"type":"link","label":"EntityWorkspace","href":"/weaverORM/de/docs/workspace","docId":"workspace","unlisted":false},{"type":"link","label":"Repositories","href":"/weaverORM/de/docs/repositories","docId":"repositories","unlisted":false},{"type":"link","label":"Query Builder","href":"/weaverORM/de/docs/querying","docId":"querying","unlisted":false},{"type":"link","label":"Lifecycle-Hooks","href":"/weaverORM/de/docs/lifecycle","docId":"lifecycle","unlisted":false},{"type":"link","label":"Transaktionen","href":"/weaverORM/de/docs/transactions","docId":"transactions","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Schema & Migrations","items":[{"type":"link","label":"Schema und Migrationen","href":"/weaverORM/de/docs/schema-migrations","docId":"schema-migrations","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Advanced","items":[{"type":"link","label":"Entity-Collections","href":"/weaverORM/de/docs/collections","docId":"collections","unlisted":false},{"type":"link","label":"Paginierung","href":"/weaverORM/de/docs/pagination","docId":"pagination","unlisted":false},{"type":"link","label":"Testen","href":"/weaverORM/de/docs/testing","docId":"testing","unlisted":false},{"type":"link","label":"Migration von Doctrine","href":"/weaverORM/de/docs/doctrine-bridge","docId":"doctrine-bridge","unlisted":false},{"type":"link","label":"MongoDB-Unterst\xfctzung","href":"/weaverORM/de/docs/mongodb","docId":"mongodb","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"ValkarnSQL","items":[{"type":"link","label":"Overview","href":"/weaverORM/de/docs/valkarnsql/overview","docId":"valkarnsql/overview","unlisted":false},{"type":"link","label":"Time Travel","href":"/weaverORM/de/docs/valkarnsql/time-travel","docId":"valkarnsql/time-travel","unlisted":false},{"type":"link","label":"Branches","href":"/weaverORM/de/docs/valkarnsql/branches","docId":"valkarnsql/branches","unlisted":false},{"type":"link","label":"CDC","href":"/weaverORM/de/docs/valkarnsql/cdc","docId":"valkarnsql/cdc","unlisted":false},{"type":"link","label":"Approximate Queries","href":"/weaverORM/de/docs/valkarnsql/approximate","docId":"valkarnsql/approximate","unlisted":false},{"type":"link","label":"Vector Search","href":"/weaverORM/de/docs/valkarnsql/vectors","docId":"valkarnsql/vectors","unlisted":false},{"type":"link","label":"WASM UDFs","href":"/weaverORM/de/docs/valkarnsql/wasm-udfs","docId":"valkarnsql/wasm-udfs","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"collections":{"id":"collections","title":"Entity-Collections","description":"Weaver\\\\ORM\\\\Collection\\\\EntityCollection is a typed, immutable-by-default collection returned by repositories and query builders. Every method that would mutate the collection returns a new EntityCollection instance, so the original is never modified. This makes collections safe to pass around without defensive copying.","sidebar":"tutorialSidebar"},"concerns":{"id":"concerns","title":"Concerns und Traits","description":"Weaver ORM provides built-in concerns \u2014 PHP traits that add common behaviour (timestamps, soft deletes, UUID generation) to entities and their mappers. They follow the same explicit-mapping philosophy: each concern contributes both the entity-side PHP logic and the mapper-side column definitions.","sidebar":"tutorialSidebar"},"configuration":{"id":"configuration","title":"Symfony-Konfiguration","description":"Weaver ORM wird \xfcber config/packages/weaver.yaml konfiguriert. Diese Seite behandelt alle verf\xfcgbaren Optionen.","sidebar":"tutorialSidebar"},"doctrine-bridge":{"id":"doctrine-bridge","title":"Migration von Doctrine","description":"Weaver ORM ships a compatibility bridge that lets you migrate an existing Doctrine ORM codebase incrementally. The bridge exposes the familiar Doctrine EntityManager API as a thin, deprecated wrapper over the Weaver internals so that existing code continues to compile and run while you migrate file by file.","sidebar":"tutorialSidebar"},"embeddable":{"id":"embeddable","title":"Eingebettete Objekte","description":"An embeddable (also called a value object in DDD terminology) is a PHP class whose properties are stored as columns in the parent entity\'s table \u2014 no join, no separate table. Weaver manages the column mapping and prefix logic via a dedicated AbstractEmbeddableMapper.","sidebar":"tutorialSidebar"},"entity-mapping":{"id":"entity-mapping","title":"Entity-Mapping","description":"Weaver ORM trennt Domain-Objekte von Persistenz-Metadaten, indem alle Mapping-Informationen in einer dedizierten Mapper-Klasse abgelegt werden. Diese Seite behandelt jeden Aspekt der Mapper-Konfiguration.","sidebar":"tutorialSidebar"},"inheritance":{"id":"inheritance","title":"Vererbungs-Mapping","description":"Weaver ORM supports three inheritance patterns. Choose based on how similar your subclass schemas are and how often you need to query across all types in a single SELECT.","sidebar":"tutorialSidebar"},"installation":{"id":"installation","title":"Installation","description":"Anforderungen","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Was ist Weaver ORM?","description":"Weaver ORM ist ein PHP 8.4+ Object-Relational Mapper (objektrelationaler Mapper) f\xfcr Symfony-Anwendungen, der auf einem einzigen Grundsatz aufbaut: Ihre Domain-Objekte sollen keinerlei Kenntnisse \xfcber die Datenbank besitzen. Keine Annotationen auf Entity-Klassen, keine Proxy-Generierung, keine Laufzeit-Reflection \u2013 nur einfache PHP-Objekte und explizite Mapper-Klassen, die die \xdcbersetzung zwischen ihnen und SQL \xfcbernehmen.","sidebar":"tutorialSidebar"},"lifecycle":{"id":"lifecycle","title":"Lifecycle-Hooks","description":"Weaver ORM provides a set of PHP 8 attributes that let you attach callbacks directly to entity methods. These callbacks are invoked at specific points in the entity\'s persistence lifecycle \u2014 before or after insert, update, delete, and load operations.","sidebar":"tutorialSidebar"},"mongodb":{"id":"mongodb","title":"MongoDB-Unterst\xfctzung","description":"Weaver ORM includes first-class support for MongoDB through a document-oriented abstraction layer. The API mirrors the relational ORM closely, so switching between SQL and MongoDB entities requires minimal mental overhead.","sidebar":"tutorialSidebar"},"pagination":{"id":"pagination","title":"Paginierung","description":"Weaver ORM provides three paginator types for different use cases: Page (standard offset pagination), SimplePage (lightweight, no total count), and CursorPage (cursor-based, ideal for infinite scroll and large datasets).","sidebar":"tutorialSidebar"},"querying":{"id":"querying","title":"Query Builder","description":"EntityQueryBuilder is Weaver ORM\'s fluent query API. It wraps Doctrine DBAL with full entity awareness: results are automatically hydrated into entity objects, global scopes are applied, and soft-delete filters are managed transparently.","sidebar":"tutorialSidebar"},"quick-start":{"id":"quick-start","title":"Schnellstart","description":"Dieser Leitfaden f\xfchrt Sie durch ein vollst\xe4ndiges, funktionierendes Beispiel: die Definition einer User-Entity, das Schreiben des zugeh\xf6rigen Mappers und die Durchf\xfchrung grundlegender Persistenzoperationen mit EntityWorkspace.","sidebar":"tutorialSidebar"},"relations":{"id":"relations","title":"Beziehungen","description":"Weaver ORM definiert alle Beziehungs-Metadaten innerhalb der Mapper-Klasse der Entity \xfcber eine RelationMap. Es gibt keine Attribute auf Entity-Eigenschaften und keine Laufzeit-Reflection. Beziehungen werden immer explizit geladen \u2014 Weaver gibt niemals \xfcberraschende Abfragen hinter Ihrem R\xfccken aus.","sidebar":"tutorialSidebar"},"repositories":{"id":"repositories","title":"Repositories","description":"Repositories are the primary way to read entities from the database. Every entity has a corresponding repository that encapsulates all query logic for that entity, keeping controllers and services free of raw SQL or query-builder calls.","sidebar":"tutorialSidebar"},"schema-migrations":{"id":"schema-migrations","title":"Schema und Migrationen","description":"Weaver ORM generates SQL DDL directly from your mapper classes. The SchemaGenerator reads every registered mapper, converts it into a Doctrine DBAL Schema object, and can create, update, or drop your database schema through a set of Symfony console commands.","sidebar":"tutorialSidebar"},"testing":{"id":"testing","title":"Testen","description":"Weaver ORM provides a dedicated testing toolkit that makes it straightforward to write fast, reliable tests for code that interacts with the database.","sidebar":"tutorialSidebar"},"transactions":{"id":"transactions","title":"Transaktionen","description":"Weaver ORM provides TransactionManager, a dedicated service for managing database transactions. It supports simple atomic blocks, manual begin/commit/rollback, nested transactions via savepoints, and optimistic locking.","sidebar":"tutorialSidebar"},"valkarnsql/approximate":{"id":"valkarnsql/approximate","title":"Approximative Abfragen","description":"Approximate Query Processing (AQP) lets ValkarnSQL answer aggregate questions \u2014 COUNT, SUM, AVG \u2014 by scanning a statistical sample of the data instead of reading every row. The result is returned in milliseconds even on tables with billions of rows, at the cost of a small, bounded error margin.","sidebar":"tutorialSidebar"},"valkarnsql/branches":{"id":"valkarnsql/branches","title":"Branching","description":"ValkarnSQL branching works like Git branches, but for data. A branch is a lightweight, copy-on-write snapshot of the entire database. It can be queried and mutated independently of its parent, then either merged back or discarded \u2014 without affecting any other branch.","sidebar":"tutorialSidebar"},"valkarnsql/cdc":{"id":"valkarnsql/cdc","title":"Change Data Capture","description":"Change Data Capture (CDC) is a technique for observing every INSERT, UPDATE, and DELETE that occurs on a database table, in real time, without polling. ValkarnSQL exposes a streaming SUBSCRIBE TO CHANGES ON  SQL command that yields rows as DML operations are committed to the WAL (Write-Ahead Log). Weaver ORM wraps this mechanism in CdcSubscriber and hydrates each row into a typed CdcEvent.","sidebar":"tutorialSidebar"},"valkarnsql/overview":{"id":"valkarnsql/overview","title":"ValkarnSQL \xdcbersicht","description":"ValkarnSQL is a custom database engine written in Rust. It speaks the PostgreSQL wire protocol version 3 natively, which means every PostgreSQL-compatible library, driver, and tool connects to it without modification \u2014 including the PDO pgsql driver that Doctrine DBAL uses under the hood.","sidebar":"tutorialSidebar"},"valkarnsql/time-travel":{"id":"valkarnsql/time-travel","title":"Zeitreise-Abfragen","description":"ValkarnSQL maintains a complete history of every row that has ever existed in the database. Time travel queries let you read data as it appeared at any previous point in time by appending an AS OF clause to the FROM clause of a SELECT statement. This is useful for audit log replay, point-in-time recovery, compliance reports, and debugging data mutations.","sidebar":"tutorialSidebar"},"valkarnsql/vectors":{"id":"valkarnsql/vectors","title":"Vektorsuche","description":"Vector similarity search lets you find rows whose stored embedding vectors are closest to a query vector. This is the foundation of semantic search, recommendation systems, and AI-powered retrieval \u2014 where \\"closeness\\" is measured by cosine distance, Euclidean (L2) distance, or dot product, rather than exact string or numeric equality.","sidebar":"tutorialSidebar"},"valkarnsql/wasm-udfs":{"id":"valkarnsql/wasm-udfs","title":"WASM UDFs","description":"ValkarnSQL supports WebAssembly User-Defined Functions (WASM UDFs) \u2014 custom SQL functions compiled to the WebAssembly binary format and executed inside the database engine. WASM UDFs run in a sandboxed, deterministic environment with near-native performance and no external network access. Once registered, they are callable from any SQL statement.","sidebar":"tutorialSidebar"},"workspace":{"id":"workspace","title":"EntityWorkspace","description":"EntityWorkspace is Weaver ORM\'s central unit-of-work service. It tracks entities across a single request, batches all writes, and flushes them to the database in a single coordinated operation. Think of it as the improved successor to Doctrine\'s EntityManager, redesigned for clarity, worker safety, and explicit intent.","sidebar":"tutorialSidebar"}}}}')}}]);